import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';

const SLIDES = [
  {
    img: 'https://images.unsplash.com/photo-1560179707-f14e90ef3623?w=1400&q=80',
    title: 'PT Abnan Inti Trans',
    sub: 'Solusi Export Import & Distribusi Alat Telekomunikasi Terpercaya',
    cta: 'Konsultasi Gratis',
  },
  {
    img: 'https://images.unsplash.com/photo-1578575437130-527eed3abbec?w=1400&q=80',
    title: 'Pengalaman 3 Tahun Global',
    sub: 'Negosiasi harga terbaik, menekan biaya pembelian 1-6 Miliar Rupiah',
    cta: 'Lihat Produk',
  },
  {
    img: 'https://images.unsplash.com/photo-1494412574643-ff11b0a5c1c3?w=1400&q=80',
    title: 'Pembayaran Mudah & Aman',
    sub: 'Tersedia via Indomaret, Alfamart, Transfer Bank, dan Midtrans',
    cta: 'Mulai Sekarang',
  },
];

const BRANDS = ['Agroplush','Huawei','Juniper','ZTE','Huawei Enterprise','Cisco','Mikrotik','TP-Link','Ruckus','Fortinet'];

const PARTNERS = [
  { name: 'Awinet', role: 'Partner Distribusi' },
  { name: 'Fen', role: 'Partner Logistik' },
  { name: 'Raju', role: 'Partner Ekspor' },
  { name: 'Tink Net', role: 'Partner Networking' },
];

const TOOLS = ['Switch Jaringan', 'Router Enterprise', 'Fiber Optic', 'Access Point', 'Server Rack', 'UPS & Power', 'Kabel Telekomunikasi', 'Antena Tower', 'Peralatan Pertanian Agroplush', 'Perangkat IoT'];

const PAYMENT_METHODS = [
  { icon: '🏪', name: 'Indomaret', desc: 'Bayar di minimarket terdekat' },
  { icon: '🏬', name: 'Alfamart', desc: 'Pembayaran mudah 24 jam' },
  { icon: '💳', name: 'Midtrans', desc: 'Kartu kredit & debit' },
  { icon: '🏦', name: 'Transfer Bank', desc: 'BCA, BRI, BNI, Mandiri' },
  { icon: '📱', name: 'E-Wallet', desc: 'GoPay, OVO, Dana, dll' },
  { icon: '🧾', name: 'Virtual Account', desc: 'VA instan semua bank' },
];

const CHATBOT_ANSWERS = {
  harga: 'Harga kami sangat kompetitif! Kami mampu menekan biaya pembelian 1-6 Miliar dari harga pasar. Silakan hubungi marketing kami di marketing@abnanintitrans.com untuk penawaran khusus.',
  produk: 'Kami menyediakan: Agroplush, Huawei, Juniper Networks, ZTE, dan banyak brand telekomunikasi lainnya. Ketik nama brand untuk info lebih detail!',
  pengiriman: 'Kami melayani export-import dengan pengalaman 3 tahun. Kami mengurus semua dokumen beacukai dan customs clearance untuk Anda.',
  pembayaran: 'Tersedia: Transfer Bank, Indomaret, Alfamart, Midtrans (kartu kredit/debit), Virtual Account, dan E-Wallet.',
  kontak: 'Hubungi kami:\n📧 marketing@abnanintitrans.com\n📞 Silakan isi form kontak di website\n📍 Kantor: Segera tersedia',
  default: 'Terima kasih telah menghubungi PT Abnan Inti Trans! Saya adalah asisten virtual kami. Anda bisa bertanya tentang: produk, harga, pengiriman, pembayaran, atau kontak kami. Ketik salah satu untuk info lebih lanjut!',
};

function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const handler = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handler);
    return () => window.removeEventListener('scroll', handler);
  }, []);

  const links = [
    { label: 'Beranda', href: '#beranda' },
    { label: 'Tentang', href: '#tentang' },
    { label: 'Produk', href: '#produk' },
    { label: 'Layanan', href: '#layanan' },
    { label: 'Kontak', href: '#kontak' },
  ];

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${scrolled ? 'bg-white shadow-md' : 'bg-transparent'}`}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">
          <div className="flex items-center gap-2">
            <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-bold text-white text-sm ${scrolled ? 'bg-blue-600' : 'bg-white bg-opacity-20'}`}>A</div>
            <span className={`font-bold text-lg ${scrolled ? 'text-gray-900' : 'text-white'}`}>Abnan Inti Trans</span>
          </div>

          {/* Desktop menu */}
          <div className="hidden md:flex items-center gap-6">
            {links.map(l => (
              <a key={l.label} href={l.href} className={`text-sm font-medium transition-colors hover:text-blue-500 ${scrolled ? 'text-gray-700' : 'text-white'}`}>{l.label}</a>
            ))}
            <Link to="/login" className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${scrolled ? 'bg-blue-600 text-white hover:bg-blue-700' : 'bg-white bg-opacity-20 text-white border border-white border-opacity-50 hover:bg-opacity-30'}`}>
              Login CRM
            </Link>
          </div>

          {/* Burger button */}
          <button className="md:hidden p-2 rounded-lg" onClick={() => setMenuOpen(!menuOpen)}>
            {menuOpen ? (
              <svg className={`w-6 h-6 ${scrolled ? 'text-gray-700' : 'text-white'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            ) : (
              <svg className={`w-6 h-6 ${scrolled ? 'text-gray-700' : 'text-white'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
              </svg>
            )}
          </button>
        </div>

        {/* Mobile menu */}
        {menuOpen && (
          <div className="md:hidden bg-white rounded-b-xl shadow-lg px-4 py-4 space-y-3 border-t">
            {links.map(l => (
              <a key={l.label} href={l.href} className="block text-gray-700 font-medium py-1 hover:text-blue-600" onClick={() => setMenuOpen(false)}>{l.label}</a>
            ))}
            <Link to="/login" className="block w-full text-center bg-blue-600 text-white px-4 py-2 rounded-lg font-medium" onClick={() => setMenuOpen(false)}>Login CRM</Link>
          </div>
        )}
      </div>
    </nav>
  );
}

function Carousel() {
  const [current, setCurrent] = useState(0);
  useEffect(() => {
    const timer = setInterval(() => setCurrent(c => (c + 1) % SLIDES.length), 5000);
    return () => clearInterval(timer);
  }, []);

  return (
    <div id="beranda" className="relative h-screen overflow-hidden">
      {SLIDES.map((slide, i) => (
        <div key={i} className={`absolute inset-0 transition-opacity duration-1000 ${i === current ? 'opacity-100' : 'opacity-0'}`}>
          <img src={slide.img} alt={slide.title} className="w-full h-full object-cover" />
          <div className="absolute inset-0 bg-gradient-to-r from-blue-900/80 to-blue-600/40" />
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="text-center text-white px-4 max-w-4xl mx-auto">
              <div className="inline-block bg-blue-500 bg-opacity-30 text-blue-100 text-xs font-semibold px-3 py-1 rounded-full mb-4 border border-blue-300 border-opacity-40">
                PT Abnan Inti Trans
              </div>
              <h1 className="text-4xl md:text-6xl font-bold mb-6 leading-tight drop-shadow-lg">{slide.title}</h1>
              <p className="text-lg md:text-xl mb-8 text-blue-100 max-w-2xl mx-auto">{slide.sub}</p>
              <div className="flex flex-col sm:flex-row gap-4 justify-center">
                <a href="#kontak" className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 rounded-xl font-semibold transition-all shadow-lg hover:shadow-xl transform hover:-translate-y-0.5">
                  {slide.cta}
                </a>
                <a href="#produk" className="border-2 border-white text-white hover:bg-white hover:text-blue-700 px-8 py-3 rounded-xl font-semibold transition-all">
                  Produk Kami
                </a>
              </div>
            </div>
          </div>
        </div>
      ))}
      {/* Dots */}
      <div className="absolute bottom-6 left-0 right-0 flex justify-center gap-2">
        {SLIDES.map((_, i) => (
          <button key={i} onClick={() => setCurrent(i)} className={`w-3 h-3 rounded-full transition-all ${i === current ? 'bg-white w-8' : 'bg-white bg-opacity-50'}`} />
        ))}
      </div>
      {/* Arrows */}
      <button onClick={() => setCurrent(c => (c - 1 + SLIDES.length) % SLIDES.length)} className="absolute left-4 top-1/2 -translate-y-1/2 bg-white bg-opacity-20 hover:bg-opacity-40 text-white w-12 h-12 rounded-full flex items-center justify-center transition-all">‹</button>
      <button onClick={() => setCurrent(c => (c + 1) % SLIDES.length)} className="absolute right-4 top-1/2 -translate-y-1/2 bg-white bg-opacity-20 hover:bg-opacity-40 text-white w-12 h-12 rounded-full flex items-center justify-center transition-all">›</button>
    </div>
  );
}

function Chatbot() {
  const [open, setOpen] = useState(false);
  const [messages, setMessages] = useState([{ from: 'bot', text: 'Halo! Saya asisten PT Abnan Inti Trans 👋 Ada yang bisa saya bantu?' }]);
  const [input, setInput] = useState('');
  const bottomRef = useRef(null);

  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages]);

  const send = () => {
    if (!input.trim()) return;
    const msg = input.trim().toLowerCase();
    setMessages(m => [...m, { from: 'user', text: input }]);
    setInput('');

    setTimeout(() => {
      let reply = CHATBOT_ANSWERS.default;
      if (msg.includes('harga') || msg.includes('biaya')) reply = CHATBOT_ANSWERS.harga;
      else if (msg.includes('produk') || msg.includes('brand') || msg.includes('alat')) reply = CHATBOT_ANSWERS.produk;
      else if (msg.includes('kirim') || msg.includes('ekspor') || msg.includes('impor') || msg.includes('beacukai')) reply = CHATBOT_ANSWERS.pengiriman;
      else if (msg.includes('bayar') || msg.includes('payment') || msg.includes('indomaret') || msg.includes('midtrans')) reply = CHATBOT_ANSWERS.pembayaran;
      else if (msg.includes('kontak') || msg.includes('email') || msg.includes('alamat') || msg.includes('telp')) reply = CHATBOT_ANSWERS.kontak;
      setMessages(m => [...m, { from: 'bot', text: reply }]);
    }, 600);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50">
      {open && (
        <div className="mb-4 w-80 bg-white rounded-2xl shadow-2xl border border-gray-200 overflow-hidden flex flex-col" style={{ height: 420 }}>
          <div className="bg-blue-600 px-4 py-3 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 bg-white rounded-full flex items-center justify-center">
                <span className="text-blue-600 font-bold text-sm">A</span>
              </div>
              <div>
                <p className="text-white font-semibold text-sm">Abnan Assistant</p>
                <p className="text-blue-200 text-xs">Online</p>
              </div>
            </div>
            <button onClick={() => setOpen(false)} className="text-white opacity-70 hover:opacity-100">✕</button>
          </div>
          <div className="flex-1 overflow-y-auto p-3 space-y-2 bg-gray-50">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.from === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-xs px-3 py-2 rounded-2xl text-sm whitespace-pre-line ${m.from === 'user' ? 'bg-blue-600 text-white rounded-br-sm' : 'bg-white text-gray-700 shadow-sm rounded-bl-sm'}`}>
                  {m.text}
                </div>
              </div>
            ))}
            <div ref={bottomRef} />
          </div>
          <div className="p-3 border-t flex gap-2">
            <input value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && send()} placeholder="Ketik pesan..." className="flex-1 border border-gray-300 rounded-xl px-3 py-2 text-sm outline-none focus:border-blue-500" />
            <button onClick={send} className="bg-blue-600 text-white w-9 h-9 rounded-xl flex items-center justify-center hover:bg-blue-700 flex-shrink-0">→</button>
          </div>
        </div>
      )}
      <button onClick={() => setOpen(!open)} className="bg-blue-600 hover:bg-blue-700 text-white w-14 h-14 rounded-full shadow-xl flex items-center justify-center transition-all transform hover:scale-110">
        {open ? <span className="text-xl">✕</span> : <span className="text-2xl">💬</span>}
      </button>
    </div>
  );
}

